config.script:
// A2 "triagem_confirmacao" (#908) — agente tipo `script` (MACRO). Comportamento = ESTE arquivo (DADO).
// Reage à resposta do paciente e DESPACHA determinístico pelo PAYLOAD do botão (não por rótulo/idioma):
//   - botão com intent 'confirmar' -> confirma o agendamento do botão TOCADO + resolve o ticket;
//   - botão com intent 'ajuda'     -> joga pra fila humana (recepção);
//   - botão sem payload/desconhecido OU texto livre -> assume posse (dono-bot) e escala pro A1 (IA).
// Mudar isto = editar este .js + re-importar (sem rebuild do MS).
//
// Injetados: event ({subject, payload_safe}), config ({tipos_botao, botao_intents, escalar_agente,
// fila_humana}), context ({agente_id}), call(), log().

var subject = event.subject || {};
var payloadSafe = event.payload_safe || {};
var selfId = String(context.agente_id || '');
var conversaId = subject.conversa_id;
if (!conversaId) throw new Error('evento sem conversa_id — triagem não aplicável');
conversaId = String(conversaId);

var tiposBotao = (config.tipos_botao || ['button', 'interactive']).map(function (t) { return String(t).toLowerCase(); });
var botaoIntents = config.botao_intents || {};
var escalarAgente = config.escalar_agente;   // id do A1
if (!escalarAgente) throw new Error("config obrigatória ausente: 'escalar_agente'");
var filaHumana = config.fila_humana || 'recepcao';

// --- helpers -----------------------------------------------------------------

function unwrap(r) { var b = (r && r.body) ? r.body : r; return (b && b.data !== undefined) ? b.data : b; }

// Ação CRÍTICA: TEM de suceder (senão vira false-success) — aborta o ramo (status=erro).
function callStrict(action, payload, oQue) {
  var r = call(action, payload);
  if (r && r.ok === false) throw new Error('ação crítica falhou (' + oQue + '): HTTP ' + (r.status_code));
  return r;
}

// Rehidrata a mensagem inbound MAIS RECENTE (a API devolve DESC; a 1ª 'in' é a mais nova).
function ultimaInbound() {
  var data = unwrap(call('ler_conversa', { conversa_id: conversaId, page: 1, per_page: 10 }));
  var msgs = (data && data.length !== undefined) ? data : (data && data.items ? data.items : null);
  if (!msgs || !msgs.length) return {};
  for (var i = 0; i < msgs.length; i++) { if (msgs[i] && msgs[i].direction === 'in') return msgs[i]; }
  return msgs[0] || {};
}

// Agendamento AMARRADO ao botão tocado (autoritativo): a mensageria correlaciona por context.id.
function agendamentoDaMensagem(msg) {
  if (msg && msg.referencia_tipo === 'agendamento' && msg.referencia_id) return String(msg.referencia_id);
  return null;
}

// Fallback: o agendamento do contexto do observador (1 por conversa, sobrescrito com vários convites).
function agendamentoDoEvento() {
  var obs = payloadSafe.observadores || [];
  for (var i = 0; i < obs.length; i++) {
    if (obs[i] && String(obs[i].id) === selfId) {
      var ctx = obs[i].contexto || {};
      if (ctx.agendamento_id) return String(ctx.agendamento_id);
    }
  }
  var ref = subject.agendamento_id || subject.referencia_id;
  return ref ? String(ref) : null;
}

function desinscreverSelf() {
  call('desinscrever_observador', { conversa_id: conversaId, observador_tipo: 'bot', observador_id: selfId });
}

// --- ramos -------------------------------------------------------------------

function ramoConfirmar(payloadBotao, msg) {
  var agendamentoId = agendamentoDaMensagem(msg) || agendamentoDoEvento();
  if (!agendamentoId) {
    // Botão 'sim' SEM agendamento vinculado (convite sem referência): não MENTE 'confirmado' nem
    // resolve às cegas — encaminha à recepção pra confirmação manual (honesto).
    callStrict('transferir_fila', { conversa_id: conversaId, fila: filaHumana }, 'transferir p/ fila humana (sim sem agendamento)');
    call('comentar', { conversa_id: conversaId, conteudo: 'Paciente confirmou presença pelo botão, mas o convite não trazia o agendamento vinculado — confira e confirme manualmente.' });
    desinscreverSelf();
    log('botão CONFIRMAR sem agendamento vinculado — encaminhado à recepção');
    return { ramo: 'confirmar_sem_agendamento', conversa_id: conversaId, payload_botao: payloadBotao };
  }
  callStrict('confirmar_agendamento', { id: agendamentoId }, 'confirmar agendamento');
  call('comentar', { conversa_id: conversaId, conteudo: 'Paciente confirmou presença pelo botão. ✅ Agendamento confirmado automaticamente.' });
  call('resolver_ticket', { conversa_id: conversaId, nota: 'Confirmação de presença concluída automaticamente.' });
  desinscreverSelf();
  log('botão CONFIRMAR — agendamento confirmado + ticket resolvido (A2, por payload)');
  return { ramo: 'confirmar', conversa_id: conversaId, payload_botao: payloadBotao, tem_agendamento: true };
}

function ramoAjuda(payloadBotao) {
  callStrict('transferir_fila', { conversa_id: conversaId, fila: filaHumana }, 'transferir p/ fila humana');
  call('comentar', { conversa_id: conversaId, conteudo: 'Paciente pediu ajuda pelo botão. Encaminhado à recepção. 🆘' });
  desinscreverSelf();
  log('botão AJUDA — encaminhado à fila humana (A2, por payload)');
  return { ramo: 'ajuda', conversa_id: conversaId, payload_botao: payloadBotao, fila: filaHumana };
}

function ramoEscala() {
  // Texto livre / botão não-reconhecido: escala pro A1 (LLM). Inscrever o A1 é o KICK do handoff.
  var agendamentoId = agendamentoDoEvento();
  callStrict('inscrever_observador', { conversa_id: conversaId, observador_tipo: 'bot', observador_id: escalarAgente, origem: 'automacao', contexto: { agendamento_id: agendamentoId } }, 'inscrever A1 (handoff)');
  call('atribuir_ticket', { conversa_id: conversaId, responsavel_id: escalarAgente, responsavel_tipo: 'bot' });
  call('comentar', { conversa_id: conversaId, conteudo: 'Resposta não-estruturada: escalado para a IA de confirmação.' });
  desinscreverSelf();
  return { ramo: 'escala', escalar_agente: escalarAgente, conversa_id: conversaId };
}

// --- fluxo -------------------------------------------------------------------

var msg = ultimaInbound();
var tipo = String(msg.tipo || '').toLowerCase();
var ehBotao = tiposBotao.indexOf(tipo) !== -1;
var payloadBotao = String(msg.payload_botao || '').trim();

if (ehBotao && payloadBotao) {
  var intent = botaoIntents[payloadBotao];
  if (intent === 'confirmar') return ramoConfirmar(payloadBotao, msg);
  if (intent === 'ajuda') return ramoAjuda(payloadBotao);
  // payload de botão NÃO mapeado → cai no escalonamento (o A1 interpreta).
}

// Botão sem payload/desconhecido OU texto livre → assume posse (dono-bot) e escala pro A1.
call('atribuir_ticket', { conversa_id: conversaId, responsavel_id: selfId, responsavel_tipo: 'bot' });
return ramoEscala();

// A0 "armar_confirmacao" (#908) — agente tipo `script` (MACRO). Comportamento = ESTE arquivo (DADO).
// Arma a confirmação: quando o convite HSM sai, inscreve o A2 (triagem) como observador-bot da
// conversa, carimbando o agendamento no contexto. Mudar isto = editar este .js + re-importar (sem rebuild).
//
// Injetados pelo runtime: event (o gatilho), config (knobs/acoes), context (ids), call(), log().
//   event.payload_safe = { conversa_id?, cliente_id?, referencia_id? (=agendamento) }
//   config = { observar_agente (id do A2), ttl_seg }
//   call(action, payload) -> { ok, status_code, body }  (só ações curadas; RBAC do SA é a jaula)

var p = event.payload_safe || {};
var observarAgente = config.observar_agente;   // id do A2 (resolvido de @triagem_confirmacao no import)
var ttlSeg = config.ttl_seg || 0;
var agendamentoId = p.referencia_id || null;   // o agendamento do convite

// Preferência: o conversa_id já vem no evento `interacoes.conversa_iniciada` (a conversa existe →
// inscreve direto, sem corrida). Fallback legado: resolve a conversa aberta pelo cliente.
var conversaId = p.conversa_id;
if (!conversaId) {
  var clienteId = p.cliente_id;
  if (!clienteId) { log('evento de envio sem conversa_id nem cliente_id — nada a armar'); return { status: 'sem_cliente' }; }
  var r = call('resolver_conversa', { cliente_id: clienteId });
  var data = (r && r.body && r.body.data) ? r.body.data : (r ? r.body : null);
  conversaId = (data && data[0] && data[0].id) ? String(data[0].id) : null;
}
if (!conversaId) { log('nenhuma conversa resolvível p/ armar'); return { status: 'sem_conversa' }; }
conversaId = String(conversaId);

var inscricao = {
  conversa_id: conversaId,
  observador_tipo: 'bot',
  observador_id: observarAgente,
  origem: 'automacao',
  contexto: { agendamento_id: agendamentoId ? String(agendamentoId) : null }
};
if (ttlSeg > 0) inscricao.expira_em = new Date(Date.now() + ttlSeg * 1000).toISOString();

call('inscrever_observador', inscricao);
log('A2 inscrito como observador da conversa (confirmação armada)');
return {
  status: 'armado',
  conversa_id: conversaId,
  observador_id: observarAgente,
  tem_agendamento: !!agendamentoId,
  ttl_seg: ttlSeg
};
